import { resolveBeatTiming, type BeatTiming } from "../timeline/beat-timing.js";
import type { TimelineEvent, WorkflowMetadata } from "../timeline/context.js";
import {
  DEFAULT_FRAME_BAR_H,
  DEFAULT_FRAME_VIDEO,
  DEFAULT_SOURCE,
  sourceToFrame,
  type Rect,
  type Size,
} from "../timeline/source-to-frame.js";

export type ProductFilmTone = "neutral" | "success" | "warning" | "danger";

const DEFAULT_STAGE: Size = { width: 1440, height: 900 };

export type NormalizedRect = {
  x: number;
  y: number;
  width: number;
  height: number;
};

export function timingFor(
  at: string,
  until: string | undefined,
  timeline: TimelineEvent[],
): BeatTiming {
  return resolveBeatTiming(at, until, timeline);
}

export function readTargetRect(
  workflow: WorkflowMetadata,
  target: string,
): NormalizedRect {
  const value = workflow.targets?.[target];
  if (!isRecord(value)) {
    throw new Error(`Annotation target "${target}" was not found.`);
  }

  const rect = {
    x: numberField(value, "x"),
    y: numberField(value, "y"),
    width: numberField(value, "width") ?? numberField(value, "w"),
    height: numberField(value, "height") ?? numberField(value, "h"),
  };

  if (
    typeof rect.x !== "number" ||
    typeof rect.y !== "number" ||
    typeof rect.width !== "number" ||
    typeof rect.height !== "number"
  ) {
    throw new Error(
      `Annotation target "${target}" must include numeric x, y, width/height fields.`,
    );
  }

  return rect as NormalizedRect;
}

export function readSourceSize(workflow: WorkflowMetadata): Size {
  return (
    sizeFromUnknown(workflow.source) ??
    sizeFromUnknown(workflow.captureSize) ??
    DEFAULT_SOURCE
  );
}

export function frameRectFor(
  rect: NormalizedRect,
  source: Size,
  chrome: "none" | "minimal" | "browser-light" | "browser-dark" = "none",
): Rect {
  const frame = chrome === "none" ? DEFAULT_STAGE : DEFAULT_FRAME_VIDEO;
  return sourceToFrame(
    { x: rect.x, y: rect.y, w: rect.width, h: rect.height },
    source,
    frame,
    chrome === "none" ? 0 : DEFAULT_FRAME_BAR_H,
  );
}

export function fullStageScale(source: Size): { scaleX: number; scaleY: number } {
  return {
    scaleX: DEFAULT_STAGE.width / source.width,
    scaleY: DEFAULT_STAGE.height / source.height,
  };
}

export function cssPx(value: number): string {
  return `${Math.round(value * 100) / 100}px`;
}

export function stableClassPart(value: string): string {
  return value.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "");
}

function sizeFromUnknown(value: unknown): Size | undefined {
  if (!isRecord(value)) return undefined;
  const width = numberField(value, "width");
  const height = numberField(value, "height");
  if (typeof width !== "number" || typeof height !== "number") return undefined;
  return { width, height };
}

function numberField(value: Record<string, unknown>, field: string): number | undefined {
  const candidate = value[field];
  return typeof candidate === "number" && Number.isFinite(candidate)
    ? candidate
    : undefined;
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}
