// Scene in-scene motion (Phase 4.5). Authored choreography of the mounted <Scene>
// DOM over the Phase 1 deterministic seek clock — the product UI itself animating
// (rows assembling, focus walking, …), NOT a camera pan. Mirrors `scene-camera.ts`:
// a PURE Node-side solver resolves authored steps (at/until beats) into plain
// per-effect instructions; an in-page controller (see scene-driver
// `buildSceneMotionScript`) applies them per seeked frame under the determinism
// contract (no will-change / GPU-layer promotion; integer-snapped geometry;
// pure-function-of-time; return-to-pristine on completion).
//
// M2 ships the `reveal` primitive. `highlight`/`cursor` (M3) and the P1 set extend
// the same step/instruction shape.

import { useWorkflowContext, type WorkflowMetadata } from "../timeline/context.js";
import { timingFor } from "./product-film-utils.js";

/**
 * A motion target within the mounted scene DOM: a CSS selector of the CONTAINER
 * whose children animate, or "auto" (the largest repeated-children container — the
 * main table/list/card grid the eligibility classifier also keys on).
 */
export type SceneMotionTarget = string;

/** Authored in-scene motion steps. Timing uses the same at/until beats as camera. */
export type SceneMotionStep =
  | {
      id: string;
      at: string;
      until?: string;
      type: "reveal";
      /** Container whose children animate. Default "auto". */
      target?: SceneMotionTarget;
      /** ms between consecutive children entering. Default 80. */
      stagger?: number;
      /** px the children rise from as they fade in. Default 12. */
      distancePx?: number;
      /** Cap on number of children animated. Default 12. */
      max?: number;
    }
  | {
      id: string;
      at: string;
      until?: string;
      type: "highlight";
      /** Container whose rows are highlighted. Default "auto". */
      target?: SceneMotionTarget;
      /** Walk the focus box down the rows over the beat. Default true. */
      walk?: boolean;
      /** Cap on rows traversed. Default 8. */
      rows?: number;
      /** Padding around the focused row, px. Default 6. */
      padPx?: number;
    }
  | {
      id: string;
      at: string;
      until?: string;
      type: "cursor";
      /** Element to move the pointer to: CSS selector, or "auto" (prominent button). */
      to?: SceneMotionTarget;
      /** Pulse-click on arrival. Default true. */
      click?: boolean;
      /** Start point as a fraction of the viewport. Default { x: 0.5, y: 0.92 }. */
      from?: { x: number; y: number };
    }
  | {
      id: string;
      at: string;
      until?: string;
      type: "type";
      /** Field to type into: CSS selector, or "auto" (first visible text input). */
      target?: SceneMotionTarget;
      /** The text typed character-by-character. */
      text: string;
      /** Show a blinking caret. Default true. */
      caret?: boolean;
    }
  | {
      id: string;
      at: string;
      until?: string;
      type: "countUp";
      /** Number element: CSS selector, or "auto" (most prominent numeric text). */
      target?: SceneMotionTarget;
      /** Start value. Default 0. */
      from?: number;
      /** End value. Default: the element's own parsed number (so it ends pristine). */
      to?: number;
      /** Display format. Default "number" (deterministic grouped integer). */
      format?: "number" | "currency" | "percent";
    }
  | {
      id: string;
      at: string;
      until?: string;
      type: "scrollTo";
      /** Content element to scroll: CSS selector, or "auto" (the mounted body). */
      target?: SceneMotionTarget;
      /** Element to bring into view (selector). Default: scroll to the bottom. */
      to?: SceneMotionTarget;
    }
  | {
      id: string;
      at: string;
      until?: string;
      type: "populate";
      /** Container whose rows stream in. Default "auto". */
      target?: SceneMotionTarget;
      /** ms between consecutive rows. Default 80. */
      stagger?: number;
      /** px the rows slide in from (horizontal). Default 16. */
      distancePx?: number;
      /** Cap on rows. Default 12. */
      max?: number;
    };

/** A solved, serializable instruction consumed by the in-page controller. */
export type SceneMotionInstruction =
  | {
      type: "reveal";
      target: string;
      startMs: number;
      endMs: number;
      stagger: number;
      distancePx: number;
      max: number;
    }
  | {
      type: "highlight";
      target: string;
      startMs: number;
      endMs: number;
      walk: boolean;
      rows: number;
      padPx: number;
    }
  | {
      type: "cursor";
      to: string;
      startMs: number;
      endMs: number;
      click: boolean;
      fromXFrac: number;
      fromYFrac: number;
    }
  | {
      type: "type";
      target: string;
      startMs: number;
      endMs: number;
      text: string;
      caret: boolean;
    }
  | {
      type: "countUp";
      target: string;
      startMs: number;
      endMs: number;
      from: number;
      /** null → the in-page controller uses the element's own parsed number. */
      to: number | null;
      format: "number" | "currency" | "percent";
    }
  | {
      type: "scrollTo";
      target: string;
      /** Selector to bring into view, or null → scroll to the bottom. */
      to: string | null;
      startMs: number;
      endMs: number;
    }
  | {
      type: "populate";
      target: string;
      startMs: number;
      endMs: number;
      stagger: number;
      distancePx: number;
      max: number;
    };

export type SceneMotionConfig = { instructions: SceneMotionInstruction[] };

export type SolveSceneMotionOptions = {
  defaultStagger?: number;
  defaultDistancePx?: number;
  defaultMax?: number;
};

/**
 * Solve authored motion steps into absolute-time instructions. PURE: same inputs →
 * same config (no DOM, no clock). Element/geometry resolution happens in-page
 * against the mounted DOM (it needs live layout), which is itself a pure function
 * of the static reconstructed DOM — so determinism holds end to end.
 */
export function solveSceneMotion(
  steps: SceneMotionStep[],
  workflow: WorkflowMetadata,
  options: SolveSceneMotionOptions = {},
): SceneMotionConfig {
  const timeline = workflow.timeline ?? [];
  const instructions: SceneMotionInstruction[] = steps.map((step) => {
    const timing = timingFor(step.at, step.until, timeline);
    if (step.type === "highlight") {
      return {
        type: "highlight",
        target: step.target ?? "auto",
        startMs: timing.startMs,
        endMs: timing.endMs,
        walk: step.walk ?? true,
        rows: Math.max(1, step.rows ?? 8),
        padPx: Math.max(0, step.padPx ?? 6),
      };
    }
    if (step.type === "cursor") {
      return {
        type: "cursor",
        to: step.to ?? "auto",
        startMs: timing.startMs,
        endMs: timing.endMs,
        click: step.click ?? true,
        fromXFrac: step.from?.x ?? 0.5,
        fromYFrac: step.from?.y ?? 0.92,
      };
    }
    if (step.type === "type") {
      return {
        type: "type",
        target: step.target ?? "auto",
        startMs: timing.startMs,
        endMs: timing.endMs,
        text: step.text ?? "",
        caret: step.caret ?? true,
      };
    }
    if (step.type === "countUp") {
      return {
        type: "countUp",
        target: step.target ?? "auto",
        startMs: timing.startMs,
        endMs: timing.endMs,
        from: step.from ?? 0,
        to: step.to ?? null,
        format: step.format ?? "number",
      };
    }
    if (step.type === "scrollTo") {
      return {
        type: "scrollTo",
        target: step.target ?? "auto",
        to: step.to ?? null,
        startMs: timing.startMs,
        endMs: timing.endMs,
      };
    }
    if (step.type === "populate") {
      return {
        type: "populate",
        target: step.target ?? "auto",
        startMs: timing.startMs,
        endMs: timing.endMs,
        stagger: Math.max(0, step.stagger ?? 80),
        distancePx: Math.max(0, step.distancePx ?? 16),
        max: Math.max(1, step.max ?? 12),
      };
    }
    return {
      type: "reveal",
      target: step.target ?? "auto",
      startMs: timing.startMs,
      endMs: timing.endMs,
      stagger: Math.max(0, step.stagger ?? options.defaultStagger ?? 80),
      distancePx: Math.max(0, step.distancePx ?? options.defaultDistancePx ?? 12),
      max: Math.max(1, step.max ?? options.defaultMax ?? 12),
    };
  });
  return { instructions };
}

/** Resolve the workflow from composition context (component convenience). */
export function solveSceneMotionFromContext(
  steps: SceneMotionStep[],
  options?: SolveSceneMotionOptions,
): SceneMotionConfig {
  const { workflow } = useWorkflowContext();
  return solveSceneMotion(steps, workflow, options);
}
