import type { ComposeNode } from "../jsx-runtime.js";
import {
  buildSceneCameraScript,
  buildSceneMotionScript,
  buildSceneMountScript,
  SCENE_ROOT_CLASS,
  type SceneArtifact,
} from "../render/scene-driver.js";
import {
  solveSceneCameraFromContext,
  type SolveSceneCameraOptions,
} from "./scene-camera.js";
import {
  solveSceneMotionFromContext,
  type SceneMotionStep,
  type SolveSceneMotionOptions,
} from "./scene-motion.js";
import type { ProductFilmStep } from "./ProductFilm.js";

export type { SceneArtifact } from "../render/scene-driver.js";

export type SceneProps = {
  /** The Phase 2 DOM artifact to mount as the scene's media layer. */
  artifact: SceneArtifact;
  chrome?: "none" | "minimal" | "browser-light" | "browser-dark";
  url?: string;
  /**
   * Authored camera move (Task 4.2). Solved via `@reshot/motion-core` (the same
   * solver `<FocusPath>`/`<ProductFilm>` use for video) and applied as an INLINE
   * per-frame transform on the scene media layer, so the zoom re-rasterizes the
   * real DOM (vector-crisp) instead of upscaling a cached bitmap.
   */
  camera?: ProductFilmStep[];
  /** Solver tuning for the camera move (motion settings + spring sample rate). */
  cameraOptions?: SolveSceneCameraOptions;
  /**
   * Authored IN-SCENE motion (Phase 4.5) — the product UI itself animating over the
   * deterministic clock (e.g. rows assembling), not a camera pan. Applied per seeked
   * frame under the determinism contract (no will-change; integer-snapped). Composes
   * with `camera` (camera transforms the layer; motion mutates the inner DOM).
   */
  motion?: SceneMotionStep[];
  /** Solver tuning for the in-scene motion. */
  motionOptions?: SolveSceneMotionOptions;
  /** Overlays (annotations etc.) rendered above the scene, same as <Frame>. */
  children?: ComposeNode;
};

/**
 * `<Scene>` mounts a reconstructed Phase 2 DOM artifact as the composition's media
 * layer — as REAL DOM inside the render page (not an <iframe>, not a cached
 * <img>/<video> bitmap). The artifact is transplanted into
 * `.reshot-frame__media-layer` by a client-side mount script (see scene-driver),
 * keeping the layer's geometry/transform-origin so a later camera move (Task 4.2)
 * re-rasterizes live DOM per frame and stays vector-crisp.
 *
 * `will-change: transform` is removed from this scene's media layer (it promotes a
 * cached GPU layer that blurs under a later zoom). Static rendering here; motion
 * is Task 4.2.
 */
export function Scene({
  artifact,
  chrome = "none",
  url = "app.reshot.dev",
  camera,
  cameraOptions,
  motion,
  motionOptions,
  children,
}: SceneProps): ComposeNode {
  const showChrome = chrome !== "none";
  const mountScript = buildSceneMountScript(artifact);
  const cameraPath =
    camera && camera.length > 0
      ? solveSceneCameraFromContext(camera, cameraOptions)
      : undefined;
  const cameraScript = buildSceneCameraScript(cameraPath);
  const motionConfig =
    motion && motion.length > 0
      ? solveSceneMotionFromContext(motion, motionOptions)
      : undefined;
  const motionScript = buildSceneMotionScript(motionConfig);

  return (
    <div className={`reshot-frame reshot-frame--${chrome}`} data-product-surface="true">
      {showChrome ? (
        <div className="reshot-frame__chrome">
          <div className="reshot-frame__traffic" aria-hidden="true">
            <span />
            <span />
            <span />
          </div>
          <div className="reshot-frame__url">{url}</div>
        </div>
      ) : null}
      <div className="reshot-frame__viewport">
        {/* Drop will-change on the scene media layer: a cached GPU layer blurs
            real DOM under a later transform-based camera zoom. */}
        <style>{".reshot-frame__media-layer--scene{will-change:auto}"}</style>
        <div className="reshot-frame__media-layer reshot-frame__media-layer--scene">
          <div
            className={SCENE_ROOT_CLASS}
            data-reshot-scene="1"
            aria-hidden="true"
          />
          <script>{mountScript}</script>
          {cameraScript ? <script>{cameraScript}</script> : null}
          {motionScript ? <script>{motionScript}</script> : null}
        </div>
        <div className="reshot-frame__overlays">{children}</div>
      </div>
    </div>
  );
}
