import type { ComposeNode } from "../jsx-runtime.js";
import {
  createWorkflowProvider,
  type WorkflowMetadata,
} from "../timeline/context.js";

export type CompositionProps = {
  workflow: WorkflowMetadata;
  slug?: string;
  capturePath?: string;
  durationMs?: number;
  children?: ComposeNode;
};

const BASE_STAGE_CSS = `
*, *::before, *::after { box-sizing: border-box; }
html, body { margin: 0; padding: 0; width: 100%; min-height: 100%; background: transparent; }
body.stage {
  margin: 0;
  font-family: ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
  color: #111827;
  -webkit-font-smoothing: antialiased;
  text-rendering: optimizeLegibility;
}
.reshot-compose-stage {
  width: 100vw;
  height: 100vh;
  position: relative;
  overflow: hidden;
  display: flex;
  align-items: center;
  justify-content: center;
  background: #ffffff;
}
.reshot-frame {
  --reshot-frame-chrome-height: 0px;
  width: 100vw;
  height: 100vh;
  position: relative;
  overflow: hidden;
  background: #ffffff;
  border: 0;
  border-radius: 0;
  box-shadow: none;
}
.reshot-frame--minimal,
.reshot-frame--browser-light,
.reshot-frame--browser-dark {
  --reshot-frame-chrome-height: 32px;
  width: min(calc(100vw - 48px), 1440px);
  height: min(calc(100vh - 48px), 900px);
  border: 1px solid rgba(15, 23, 42, 0.16);
  border-radius: 10px;
}
.reshot-frame__chrome {
  height: var(--reshot-frame-chrome-height);
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 0 12px;
  border-bottom: 1px solid rgba(15, 23, 42, 0.1);
  background: #f8fafc;
}
.reshot-frame--browser-dark .reshot-frame__chrome {
  border-bottom-color: rgba(255, 255, 255, 0.12);
  background: rgba(17, 24, 39, 0.92);
}
.reshot-frame__traffic {
  display: flex;
  gap: 7px;
}
.reshot-frame__traffic span {
  width: 11px;
  height: 11px;
  border-radius: 999px;
  display: block;
}
.reshot-frame__traffic span:nth-child(1) { background: #ff5f57; }
.reshot-frame__traffic span:nth-child(2) { background: #febc2e; }
.reshot-frame__traffic span:nth-child(3) { background: #28c840; }
.reshot-frame__url {
  flex: 1;
  min-width: 0;
  display: flex;
  align-items: center;
  justify-content: flex-start;
  color: #475569;
  font: 500 11px ui-monospace, SFMono-Regular, Menlo, monospace;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}
.reshot-frame--browser-dark .reshot-frame__url {
  color: #cbd5e1;
}
.reshot-frame__viewport {
  position: absolute;
  top: var(--reshot-frame-chrome-height);
  left: 0;
  right: 0;
  bottom: 0;
  overflow: hidden;
  background: #ffffff;
}
.reshot-frame__media-layer {
  position: absolute;
  inset: 0;
  transform-origin: top left;
  will-change: transform;
}
.reshot-frame__media {
  width: 100%;
  height: 100%;
  display: block;
  object-fit: contain;
  background: #ffffff;
}
.reshot-frame__media--cover {
  object-fit: cover;
}
.reshot-frame__overlays {
  position: absolute;
  inset: 0;
  pointer-events: none;
  transform-origin: top left;
  will-change: transform;
}
.reshot-product-film {
  width: 100%;
  height: 100%;
}
.reshot-annotation {
  position: absolute;
  z-index: 4;
  opacity: 0;
  pointer-events: none;
  color: #0f172a;
}
.reshot-annotation__ring {
  position: absolute;
  inset: 0;
  border: 2px solid currentColor;
  border-radius: 8px;
  box-shadow: 0 0 0 2px rgba(255, 255, 255, 0.82);
}
.reshot-annotation__label {
  position: absolute;
  left: 0;
  top: 100%;
  margin-top: 8px;
  max-width: 260px;
  padding: 6px 8px;
  border-radius: 6px;
  background: rgba(255, 255, 255, 0.96);
  border: 1px solid rgba(15, 23, 42, 0.14);
  box-shadow: 0 6px 18px rgba(15, 23, 42, 0.12);
  font: 600 12px/1.25 -apple-system, BlinkMacSystemFont, "Inter", sans-serif;
}
.reshot-annotation--success { color: #147a3d; }
.reshot-annotation--warning { color: #9a5b00; }
.reshot-annotation--danger { color: #b4232d; }
.reshot-annotation--edge {
  width: auto !important;
  height: auto !important;
  max-width: 320px;
}
.reshot-annotation--edge .reshot-annotation__ring {
  display: none;
}
.reshot-annotation--edge .reshot-annotation__label {
  position: static;
  margin: 0;
}
@keyframes annotationIn {
  0% { opacity: 0; transform: translateY(4px); }
  100% { opacity: 1; transform: translateY(0); }
}
@keyframes annotationOut {
  0% { opacity: 1; transform: translateY(0); }
  100% { opacity: 0; transform: translateY(-4px); }
}
`;

export function Composition({
  workflow,
  slug = "composition",
  capturePath,
  durationMs,
  children,
}: CompositionProps): ComposeNode {
  const resolvedCapturePath =
    capturePath ?? (typeof workflow.capturePath === "string" ? workflow.capturePath : undefined);
  const resolvedDuration = durationMs ?? workflow.durationMs;

  return createWorkflowProvider(
    { workflow, slug, capturePath: resolvedCapturePath },
    <html lang="en">
      <head>
        <meta charSet="utf-8" />
        <meta name="viewport" content="width=device-width, initial-scale=1" />
        <title>{slug}</title>
        <style>{BASE_STAGE_CSS}</style>
      </head>
      <body className="stage">
        <main
          className="reshot-compose-stage"
          data-slug={slug}
          data-duration-ms={resolvedDuration}
        >
          {children}
        </main>
        <script>window.__RESHOT_COMPOSE_READY__ = true;</script>
      </body>
    </html>,
  );
}
