import type { ComposeNode } from "../jsx-runtime.js";
import { useWorkflowContext } from "../timeline/context.js";
import {
  cssPx,
  frameRectFor,
  readSourceSize,
  readTargetRect,
  stableClassPart,
  timingFor,
  type ProductFilmTone,
} from "./product-film-utils.js";
import type { FrameProps } from "./Frame.js";

export type AnnotationProps = {
  at: string;
  until?: string;
  target?: string;
  edge?: "top-left" | "top-right" | "bottom-left" | "bottom-right";
  chrome?: FrameProps["chrome"];
  tone?: ProductFilmTone;
  label?: ComposeNode;
  children?: ComposeNode;
};

const ANNOTATION_IN_MS = 180;
const ANNOTATION_OUT_MS = 140;

export function Annotation({
  at,
  until,
  target,
  edge,
  chrome = "none",
  tone = "neutral",
  label,
  children,
}: AnnotationProps): ComposeNode {
  if (!target && !edge) {
    throw new Error("Annotation requires either a target or an explicit edge placement.");
  }

  const { workflow } = useWorkflowContext();
  const timing = timingFor(at, until, workflow.timeline ?? []);
  const className = `reshot-annotation-timing-${stableClassPart(
    target ?? edge ?? at,
  )}-${stableClassPart(at)}`;
  const content = children ?? label;
  const timingStyle = (
    <style>{`
.${className} {
  animation:
    annotationIn ${ANNOTATION_IN_MS}ms ${timing.startMs}ms ease-out forwards,
    annotationOut ${ANNOTATION_OUT_MS}ms ${timing.endMs}ms ease-in forwards;
}
`}</style>
  );

  if (target) {
    const source = readSourceSize(workflow);
    const frameRect = frameRectFor(readTargetRect(workflow, target), source, chrome);
    return (
      <>
        {timingStyle}
        <div
          className={`reshot-annotation reshot-annotation--${tone} ${className}`}
          data-annotation-target={target}
          style={{
            left: cssPx(frameRect.x),
            top: cssPx(frameRect.y),
            width: cssPx(frameRect.w),
            height: cssPx(frameRect.h),
          }}
        >
          <span className="reshot-annotation__ring" />
          {content ? <span className="reshot-annotation__label">{content}</span> : null}
        </div>
      </>
    );
  }

  return (
    <>
      {timingStyle}
      <div
        className={`reshot-annotation reshot-annotation--edge reshot-annotation--${tone} ${className}`}
        data-annotation-edge={edge}
        style={edgeStyle(edge)}
      >
        {content ? <span className="reshot-annotation__label">{content}</span> : null}
      </div>
    </>
  );
}

function edgeStyle(edge: AnnotationProps["edge"]): Record<string, string> {
  const inset = "20px";
  switch (edge) {
    case "top-right":
      return { top: inset, right: inset };
    case "bottom-left":
      return { bottom: inset, left: inset };
    case "bottom-right":
      return { bottom: inset, right: inset };
    case "top-left":
    default:
      return { top: inset, left: inset };
  }
}
