// Scene camera path (Phase 4, Task 4.2).
//
// Solves an authored camera move over a mounted <Scene> DOM artifact by reusing
// `@reshot/motion-core` (the SAME solver `<FocusPath>` drives for video) and emits
// the solved keyframes as plain data. The data is consumed by an in-page controller
// (see scene-driver `buildSceneCameraScript`) that sets the media layer's transform
// INLINE per seeked frame — NOT via a CSS `@keyframes` animation.
//
// Why inline-per-frame instead of a CSS animation (the FocusPath path):
//   A running CSS/WAAPI animation lets the compositor cache the element as a
//   texture and re-use it across frames; zooming that cached texture upscales a
//   bitmap → text blurs. Setting `transform` inline as a fresh style each seeked
//   frame forces a layout/paint at the zoomed scale, so the browser re-rasterizes
//   the real DOM vector text at full resolution. That re-rasterization is the
//   entire point of mounting real DOM (Task 4.1) and is what this task proves.
//
// The solver math is NOT reimplemented here — `solveCameraPath` from motion-core
// is the single source of truth, exactly as `<FocusPath>` uses it.

import { useWorkflowContext, type WorkflowMetadata } from "../timeline/context.js";
import {
  solveProductFilmCameraPath,
  type CameraSolverSettings,
} from "./camera-solver.js";
import type { ProductFilmStep } from "./ProductFilm.js";

/** A solved keyframe in absolute composition time, viewport in source pixels. */
export type SceneCameraKeyframe = {
  /** Absolute time from composition start, in ms. */
  tMs: number;
  /** Top-left of the viewport in SOURCE (captured) pixels. */
  x: number;
  /** Top-left of the viewport in SOURCE (captured) pixels. */
  y: number;
  /** Zoom (1.0 = full source). */
  zoom: number;
  isHardCut: boolean;
};

export type SceneCameraPath = {
  keyframes: SceneCameraKeyframe[];
  /** Source (captured) dimensions the keyframe coordinates are expressed in. */
  source: { width: number; height: number };
};

/**
 * Solve an authored `ProductFilmStep[]` camera move into absolute-time keyframes
 * in SOURCE pixel space. Pure (no DOM): same inputs → same keyframes. Mirrors the
 * solver wiring in `<FocusPath>` so authored moves render identically on video and
 * on a `<Scene>` — the only difference is HOW the transform is applied per frame.
 */
export type SolveSceneCameraOptions = {
  /**
   * Motion settings forwarded to the solver. Defaults mirror `<FocusPath>`
   * (cinematic / damping 0.55 / padding 2.4).
   */
  settings?: CameraSolverSettings;
  /**
   * Spring sample interval in ms. Step-boundary sampling (the default when unset)
   * only emits one keyframe per step, so a single push-in never reaches its target
   * mid-flight. Passing a small interval (e.g. the frame period) samples the spring
   * densely so the camera actually arrives at the zoomed framing. The in-page
   * controller interpolates between whatever keyframes it is given.
   */
  sampleIntervalMs?: number;
};

export function solveSceneCameraPath(
  steps: ProductFilmStep[],
  workflow: WorkflowMetadata,
  options: SolveSceneCameraOptions = {},
): SceneCameraPath {
  const { source, timedSteps, solved } = solveProductFilmCameraPath(
    steps,
    workflow,
    options,
  );

  if (timedSteps.length === 0) {
    return { keyframes: [], source };
  }

  const firstStartMs = timedSteps[0]?.timing.startMs ?? 0;
  const keyframes: SceneCameraKeyframe[] = solved.map((frame) => ({
    tMs: firstStartMs + frame.timeMs,
    x: frame.viewport.x,
    y: frame.viewport.y,
    zoom: frame.viewport.zoom,
    isHardCut: frame.isHardCut,
  }));

  return { keyframes, source };
}

/** Resolve the steps + workflow from context (component convenience). */
export function solveSceneCameraFromContext(
  steps: ProductFilmStep[],
  options?: SolveSceneCameraOptions,
): SceneCameraPath {
  const { workflow } = useWorkflowContext();
  // Sample the spring at ~60fps by default so an authored push-in actually
  // reaches its zoomed framing (step-boundary sampling would not move the camera
  // within a single step).
  return solveSceneCameraPath(steps, workflow, {
    ...options,
    sampleIntervalMs: options?.sampleIntervalMs ?? 1000 / 60,
  });
}
