export type Rect = {
  x: number;
  y: number;
  w: number;
  h: number;
};

export type Size = {
  width: number;
  height: number;
};

export const DEFAULT_SOURCE: Size = { width: 1440, height: 900 };
export const DEFAULT_FRAME_VIDEO: Size = { width: 1280, height: 800 };
export const DEFAULT_FRAME_BAR_H = 36;

export function sourceToFrame(
  rect: Rect,
  source: Size = DEFAULT_SOURCE,
  frame: Size = DEFAULT_FRAME_VIDEO,
  barH = DEFAULT_FRAME_BAR_H,
): Rect {
  const scaleX = frame.width / source.width;
  const scaleY = frame.height / source.height;

  return {
    x: rect.x * scaleX,
    y: barH + rect.y * scaleY,
    w: rect.w * scaleX,
    h: rect.h * scaleY,
  };
}
