export type ComposeNode =
  | ComposeElement
  | string
  | number
  | boolean
  | null
  | undefined
  | ComposeNode[];

export type ComposeComponent<P = Record<string, unknown>> = (
  props: P & { children?: ComposeNode },
) => ComposeNode;

export type ComposeElementType = string | ComposeComponent | symbol;

export interface ComposeElement {
  readonly $$compose: true;
  type: ComposeElementType;
  props: Record<string, unknown>;
  children: ComposeNode[];
  key?: string;
}

export const Fragment: unique symbol = Symbol("Fragment");

export function normalizeChildren(value: unknown): ComposeNode[] {
  if (value == null || value === false || value === true) return [];
  if (Array.isArray(value)) return value.flatMap(normalizeChildren);
  return [value as ComposeNode];
}

export function jsx(
  type: ComposeElementType,
  props: Record<string, unknown> | null,
  key?: string,
): ComposeElement {
  const nextProps = props ?? {};
  const { children, ...rest } = nextProps;

  return {
    $$compose: true,
    type,
    props: rest,
    children: normalizeChildren(children),
    key,
  };
}

export function jsxs(
  type: ComposeElementType,
  props: Record<string, unknown> | null,
  key?: string,
): ComposeElement {
  return jsx(type, props, key);
}

export const jsxDEV = jsx;

type ComposeIntrinsicProps = {
  className?: string;
  id?: string;
  style?: Record<string, string | number | null | undefined | false>;
  children?: ComposeNode;
} & Record<string, unknown>;

export namespace JSX {
  export type Element = ComposeNode;
  export interface ElementChildrenAttribute {
    children: ComposeNode;
  }
  export interface IntrinsicElements {
    [tag: string]: ComposeIntrinsicProps;
  }
}
