// Scene mount path (Phase 4, Task 4.1).
//
// A `<Scene>` renders a Phase 2 DOM artifact as the composition's media layer —
// as REAL DOM inside the render page, NOT an <iframe> or a cached <img>/<video>
// bitmap. Real DOM is what lets a later camera zoom (Task 4.2) re-rasterize text
// crisply per frame instead of upscaling a flat capture.
//
// The artifact is a self-contained `<!doctype html>` document (inlined
// fonts/images, baked sidecars). Mounting it inside the composition's own
// document is a two-part problem:
//   1. STYLE ISOLATION — the artifact's <head> carries a few global rules
//      (`html,body{margin:0;background}`, `*{box-sizing}`, `[data-hybrid-id]{…}`)
//      plus @font-face. Injected verbatim these would clobber the compose stage
//      (the artifact's `body{background:#fff}` would repaint the whole frame).
//      We scope every non-@font-face rule under the media-layer root and rewrite
//      bare `html`/`body` selectors onto that root, so the artifact's globals
//      apply ONLY to the artifact subtree. @font-face is keyed by family name and
//      harmless, so it is injected as-is (the artifact's inlined element styles
//      reference those families).
//   2. GEOMETRY — the artifact's <body> children are transplanted into
//      `.reshot-frame__media-layer` (which keeps the stage's `position:absolute;
//      inset:0; transform-origin:top left`). The mount root is sized to the
//      captured viewport and pinned top-left so element geometry matches the live
//      capture 1:1. Scrolls are restored exactly as `remount.ts` does.
//
// `will-change: transform` is DROPPED on the artifact media layer: it promotes a
// cached GPU layer that, while fine for a static still, would blur the DOM under a
// later transform-based camera zoom — the whole reason Scene mounts real DOM.

/** The artifact payload a <Scene> mounts. */
export type SceneArtifact = {
  /** Self-contained `<!doctype html>` document from Phase 2 capture. */
  html: string;
  /** Per-container scroll offsets to restore (same shape as CaptureSnapshot.scrolls). */
  scrolls?: { sel: string; x: number; y: number }[];
  /** Captured viewport the artifact was serialized at (defaults to the frame size). */
  viewport?: { width: number; height: number };
};

/** Marker class the mount script targets; emitted by the Scene primitive. */
export const SCENE_ROOT_CLASS = "reshot-scene-root";
export const SCENE_DATA_ATTR = "data-reshot-scene";

/**
 * Body of the in-page mount routine. Runs inside the render page (stringified
 * into a <script>), so it must be fully self-contained — it reads the artifact
 * from a global the Scene primitive writes. Idempotent: a second invocation is a
 * no-op (guards on the mounted marker).
 */
/* istanbul ignore next -- runs in the browser, exercised via the render pipeline */
function mountSceneInPage(): void {
  type Payload = {
    html: string;
    scrolls: { sel: string; x: number; y: number }[];
    viewport?: { width: number; height: number };
  };
  const w = window as unknown as {
    __RESHOT_SCENE__?: Payload;
    __RESHOT_SCENE_MOUNTED__?: boolean;
  };
  const payload = w.__RESHOT_SCENE__;
  if (!payload || w.__RESHOT_SCENE_MOUNTED__) return;

  const root = document.querySelector<HTMLElement>(
    "[data-reshot-scene='1'].reshot-scene-root",
  );
  if (!root) return;

  // Parse the self-contained artifact document offline (no navigation).
  const doc = new DOMParser().parseFromString(payload.html, "text/html");

  // Carry only writing direction from the artifact root. We deliberately do NOT
  // copy the artifact's <html>/<body> *computed inline styles* onto our mount
  // containers: the serializer bakes layout longhands (position:static,
  // width/height = content size, box-sizing) into them, and inlined onto a
  // container they would override the frame geometry (collapsing the mount to the
  // content height and unpinning it). The artifact body's CHILDREN keep their own
  // inline styles and flow correctly from the top of the mount; the root
  // background comes from the scoped html/body rule below.
  const dir = doc.documentElement.getAttribute("dir");

  // Scope + inject the artifact's <head> styles. @font-face is global-safe and
  // injected verbatim; everything else is scoped under the mount root and its
  // bare html/body selectors are rewritten onto the root, so the artifact's
  // globals never leak onto the compose stage.
  const scopeSel = "[data-reshot-scene='1'].reshot-scene-root";
  const scopeRule = (rule: CSSRule): string => {
    if (rule instanceof CSSFontFaceRule) return rule.cssText; // family-keyed, global
    if (rule instanceof CSSStyleRule) {
      const selectors = rule.selectorText.split(",").map((sel) => {
        const s = sel.trim();
        // Bare html/body/:root → the mount root itself.
        if (/^(html|body|:root)$/i.test(s)) return scopeSel;
        // html body, body * etc. → strip the html/body prefix, scope the rest.
        const stripped = s.replace(/^\s*(html|body|:root)\b\s*/i, "");
        return `${scopeSel} ${stripped || "*"}`.trim();
      });
      return `${selectors.join(", ")}{${rule.style.cssText}}`;
    }
    // @media / @supports etc.: keep as-is (rare in artifacts; safe).
    return rule.cssText;
  };

  const collected: string[] = [];
  for (const styleEl of Array.from(doc.head.querySelectorAll("style"))) {
    // Re-parse each <style> through a detached sheet to enumerate rules robustly.
    const probe = document.createElement("style");
    probe.textContent = styleEl.textContent || "";
    document.head.appendChild(probe);
    const sheet = probe.sheet;
    try {
      if (sheet) {
        for (const rule of Array.from(sheet.cssRules)) collected.push(scopeRule(rule));
      } else {
        collected.push(styleEl.textContent || "");
      }
    } finally {
      probe.remove();
    }
  }

  const scopedStyle = document.createElement("style");
  scopedStyle.setAttribute("data-reshot-scene-styles", "1");
  scopedStyle.textContent = collected.join("\n");
  document.head.appendChild(scopedStyle);

  // Size the mount root to the captured viewport, pinned top-left, so the
  // artifact's element geometry lines up 1:1 with the live capture. The parent
  // media layer already provides position:absolute; inset:0; transform-origin.
  if (payload.viewport) {
    root.style.width = `${payload.viewport.width}px`;
    root.style.height = `${payload.viewport.height}px`;
  } else {
    root.style.width = "100%";
    root.style.height = "100%";
  }
  root.style.position = "absolute";
  root.style.top = "0";
  root.style.left = "0";
  root.style.overflow = "hidden";
  if (dir) root.setAttribute("dir", dir);

  // Transplant the artifact <body> content as REAL DOM into the mount root. The
  // wrapper fills the root and establishes the block formatting context the
  // artifact body provided; its children flow from the top exactly as on the live
  // page (the artifact's `html,body{margin:0}` is reproduced by the scoped rule).
  const bodyWrap = document.createElement("div");
  bodyWrap.setAttribute("data-reshot-scene-body", "1");
  bodyWrap.style.position = "absolute";
  bodyWrap.style.inset = "0";
  while (doc.body && doc.body.firstChild) {
    bodyWrap.appendChild(document.adoptNode(doc.body.firstChild));
  }
  root.appendChild(bodyWrap);

  // Restore scroll offsets exactly as the offline remount does. ":root" maps to
  // the mount root (the artifact's scroll container inside the frame), not the
  // compose window which must stay pinned.
  for (const s of payload.scrolls || []) {
    if (s.sel === ":root") {
      bodyWrap.scrollLeft = s.x;
      bodyWrap.scrollTop = s.y;
      continue;
    }
    const el = bodyWrap.querySelector<HTMLElement>(s.sel);
    if (el) {
      el.scrollLeft = s.x;
      el.scrollTop = s.y;
    }
  }

  w.__RESHOT_SCENE_MOUNTED__ = true;
}

/** Source text of the in-page mount routine, for stringifying into a <script>. */
export const MOUNT_SCENE_SOURCE = `(${mountSceneInPage.toString()})();`;

// ── Scene camera controller (Task 4.2) ──────────────────────────────────────
//
// Drives an authored camera move over the mounted scene by setting the media
// layer's `transform` INLINE per seeked frame. It hooks the Phase 1 deterministic
// clock: on every `__composeSeek(tMs)` the seek-clock flushes queued rAF callbacks
// with `tMs`, so a self-rescheduling rAF loop runs exactly once per frame with the
// seeked time. At each tick it interpolates the solved keyframes at `tMs` and writes
// a fresh inline `transform` — forcing the browser to re-paint (re-rasterize) the
// real DOM at the zoomed scale rather than upscaling a cached compositor texture.
//
// Determinism is inherited: `tMs` is fully determined by the frame index, so the
// transform per frame is bit-for-bit reproducible.

export type SceneCameraKeyframeWire = {
  tMs: number;
  x: number;
  y: number;
  zoom: number;
  isHardCut: boolean;
};

export type SceneCameraConfig = {
  keyframes: SceneCameraKeyframeWire[];
  source: { width: number; height: number };
};

/* istanbul ignore next -- runs in the browser, exercised via the render pipeline */
function sceneCameraInPage(): void {
  type KF = { tMs: number; x: number; y: number; zoom: number; isHardCut: boolean };
  const w = window as unknown as {
    __RESHOT_SCENE_CAMERA__?: { keyframes: KF[]; source: { width: number; height: number } };
    requestAnimationFrame: (cb: (t: number) => void) => number;
    performance: { now: () => number };
  };
  const cfg = w.__RESHOT_SCENE_CAMERA__;
  if (!cfg || cfg.keyframes.length === 0) return;

  const layer = document.querySelector<HTMLElement>(
    ".reshot-frame__media-layer--scene",
  );
  if (!layer) return;

  const kfs = cfg.keyframes.slice().sort((a, b) => a.tMs - b.tMs);

  // Map a source-pixel viewport {x,y,zoom} to a CSS transform on the media layer.
  // The layer is sized to the frame; its content (the mount root) is the captured
  // source at scale = frameSize / sourceSize (= 1 for a Scene rendered at the
  // capture viewport, but measured for robustness). transform-origin is top-left.
  const applyViewport = (x: number, y: number, zoom: number): void => {
    const rect = layer.getBoundingClientRect();
    const scaleX = cfg.source.width > 0 ? rect.width / cfg.source.width : 1;
    const scaleY = cfg.source.height > 0 ? rect.height / cfg.source.height : 1;
    const tx = Math.round(-x * scaleX * zoom * 100) / 100;
    const ty = Math.round(-y * scaleY * zoom * 100) / 100;
    const z = Math.round(zoom * 1000) / 1000;
    layer.style.transform = `translate(${tx}px, ${ty}px) scale(${z})`;
  };

  const first = kfs[0]!;
  const lastKf = kfs[kfs.length - 1]!;
  const viewportAt = (t: number): { x: number; y: number; zoom: number } => {
    if (t <= first.tMs) return first;
    if (t >= lastKf.tMs) return lastKf;
    for (let i = 1; i < kfs.length; i++) {
      const b = kfs[i]!;
      if (t <= b.tMs) {
        const a = kfs[i - 1]!;
        // Hard cuts snap (no interpolation across the boundary).
        if (b.isHardCut) return a;
        const span = b.tMs - a.tMs;
        const f = span > 0 ? (t - a.tMs) / span : 1;
        return {
          x: a.x + (b.x - a.x) * f,
          y: a.y + (b.y - a.y) * f,
          zoom: a.zoom + (b.zoom - a.zoom) * f,
        };
      }
    }
    return lastKf;
  };

  // Pin the start frame immediately (frame 0 before any seek loop tick).
  applyViewport(first.x, first.y, first.zoom);

  // Self-rescheduling rAF loop, advanced one tick per __composeSeek. `t` is the
  // virtualized seek time (performance.now() === seek vt under the clock).
  const tick = (): void => {
    const t = w.performance.now();
    const v = viewportAt(t);
    applyViewport(v.x, v.y, v.zoom);
    w.requestAnimationFrame(tick);
  };
  w.requestAnimationFrame(tick);
}

/** Source text of the in-page camera routine, for stringifying into a <script>. */
export const SCENE_CAMERA_SOURCE = `(${sceneCameraInPage.toString()})();`;

/**
 * Build the inline <script> a <Scene camera=...> emits: writes the solved camera
 * config to a window global and starts the per-frame controller. Returns "" when
 * there is no camera move so static scenes stay untouched.
 */
export function buildSceneCameraScript(config: SceneCameraConfig | undefined): string {
  if (!config || config.keyframes.length === 0) return "";
  const json = JSON.stringify(config).replace(/<\/(script)/gi, "<\\/$1");
  return `window.__RESHOT_SCENE_CAMERA__ = ${json};\n${SCENE_CAMERA_SOURCE}`;
}

// ── In-scene motion controller (Phase 4.5, M2) ───────────────────────────────
//
// Animates the mounted scene DOM itself (the product UI) per seeked frame — the
// thing a flat video can't do. Built on the M1 DETERMINISM CONTRACT, which the
// real-screen stress harness proved is what keeps it byte-reproducible:
//   1. every per-frame style is a pure function of the seeked time + geometry
//      captured once at init,
//   2. NO `will-change` / GPU-layer promotion (its compositor rasterization is not
//      bit-identical across runs — the root cause of the observed flake),
//   3. integer-snapped transforms/geometry (no fractional sub-pixel rasterization),
//   4. deterministic init (first tick after mount; same layout every run),
//   5. return-to-pristine — clear the inline props an effect set once it completes,
//      so the settled DOM is byte-identical to the static reconstruction.

export type SceneMotionInstructionWire =
  | { type: "reveal"; target: string; startMs: number; endMs: number; stagger: number; distancePx: number; max: number }
  | { type: "highlight"; target: string; startMs: number; endMs: number; walk: boolean; rows: number; padPx: number }
  | { type: "cursor"; to: string; startMs: number; endMs: number; click: boolean; fromXFrac: number; fromYFrac: number }
  | { type: "type"; target: string; startMs: number; endMs: number; text: string; caret: boolean }
  | { type: "countUp"; target: string; startMs: number; endMs: number; from: number; to: number | null; format: "number" | "currency" | "percent" }
  | { type: "scrollTo"; target: string; to: string | null; startMs: number; endMs: number }
  | { type: "populate"; target: string; startMs: number; endMs: number; stagger: number; distancePx: number; max: number };

export type SceneMotionConfig = { instructions: SceneMotionInstructionWire[] };

/* istanbul ignore next -- runs in the browser, exercised via the render pipeline */
function sceneMotionInPage(): void {
  type Inst = {
    type: string;
    target?: string;
    to?: string | number | null;
    startMs: number;
    endMs: number;
    stagger?: number;
    distancePx?: number;
    max?: number;
    walk?: boolean;
    rows?: number;
    padPx?: number;
    click?: boolean;
    fromXFrac?: number;
    fromYFrac?: number;
    text?: string;
    caret?: boolean;
    from?: number;
    format?: string;
  };
  type Rect = { top: number; left: number; width: number; height: number };
  const w = window as unknown as {
    __RESHOT_SCENE_MOTION__?: { instructions: Inst[] };
    requestAnimationFrame: (cb: (t: number) => void) => number;
    performance: { now: () => number };
  };
  const cfg = w.__RESHOT_SCENE_MOTION__;
  if (!cfg || !cfg.instructions || cfg.instructions.length === 0) return;
  const layer = document.querySelector<HTMLElement>(".reshot-frame__media-layer--scene");
  if (!layer) return;

  const ease = (x: number): number => {
    const c = x < 0 ? 0 : x > 1 ? 1 : x;
    return 1 - Math.pow(1 - c, 3);
  };
  // Quantize an alpha 0..1 to the 8-bit grid (determinism rule 3 for opacity).
  const q8 = (a: number): string => String(Math.round((a < 0 ? 0 : a > 1 ? 1 : a) * 255) / 255);
  // Element rect relative to the media layer (integer-snapped at read).
  const rectRel = (el: Element, lr: DOMRect): Rect => {
    const r = el.getBoundingClientRect();
    return { top: r.top - lr.top, left: r.left - lr.left, width: r.width, height: r.height };
  };
  // Position/size an overlay box with integer-snapped geometry (rule 3).
  const setBox = (el: HTMLElement, top: number, left: number, width: number, height: number): void => {
    el.style.top = Math.round(top) + "px";
    el.style.left = Math.round(left) + "px";
    el.style.width = Math.round(width) + "px";
    el.style.height = Math.round(height) + "px";
  };
  // The most prominent visible button-like element (cursor "auto" target).
  const resolveButton = (body: HTMLElement): Element | null => {
    const cands = body.querySelectorAll("button, [role='button'], a[href]");
    let best: Element | null = null;
    let bestScore = 0;
    for (let i = 0; i < cands.length; i++) {
      const r = cands[i]!.getBoundingClientRect();
      if (r.width < 40 || r.height < 18 || r.width > 480) continue;
      // Favor prominent, upper, right-leaning controls (primary actions).
      const score = r.width * r.height + r.left + (2000 - r.top);
      if (score > bestScore) { bestScore = score; best = cands[i]!; }
    }
    return best;
  };

  // Resolve a target to the list of child elements that animate. "auto" = the
  // largest repeated-children container (the main table/list/card grid).
  const resolveRows = (body: HTMLElement, target: string, max: number): HTMLElement[] => {
    let container: Element | null = null;
    if (target && target !== "auto") {
      container = body.querySelector(target);
    } else {
      // "auto" = the most prominent VISIBLE list/table: a large container whose
      // children are several wide, row-like elements. Score by rowCount × area so
      // we land on the main content list, not a hidden many-child wrapper. (Crude
      // max-child-count picks invisible/structural containers — see M2 notes.)
      let best: Element | null = null;
      let bestScore = 0;
      let fallback: Element | null = null;
      let fallbackKids = 0;
      const all = body.getElementsByTagName("*");
      for (let i = 0; i < all.length; i++) {
        const el = all[i]!;
        const kids = el.children;
        if (kids.length > fallbackKids) { fallbackKids = kids.length; fallback = el; }
        const rect = el.getBoundingClientRect();
        if (rect.width < 200 || rect.height < 80) continue;
        let rowCount = 0;
        for (let j = 0; j < kids.length; j++) {
          const kr = kids[j]!.getBoundingClientRect();
          if (kr.height >= 24 && kr.height <= 320 && kr.width >= rect.width * 0.5) rowCount++;
        }
        if (rowCount >= 3) {
          const score = rowCount * rect.width * Math.min(rect.height, 1200);
          if (score > bestScore) { bestScore = score; best = el; }
        }
      }
      // Fall back to the largest-child-count container so "auto" always resolves.
      container = best || (fallbackKids >= 3 ? fallback : null);
    }
    if (!container) return [];
    const out: HTMLElement[] = [];
    const kids = container.children;
    for (let i = 0; i < kids.length && out.length < max; i++) {
      const el = kids[i] as HTMLElement;
      const r = el.getBoundingClientRect();
      if (r.height >= 16 && r.width >= 60) out.push(el);
    }
    return out;
  };

  // First visible text input (type "auto"), or an explicit selector.
  const resolveInput = (body: HTMLElement, target: string): HTMLElement | null => {
    if (target && target !== "auto") return body.querySelector<HTMLElement>(target);
    const cands = body.querySelectorAll<HTMLElement>(
      "input[type='text'], input[type='search'], input:not([type]), textarea, [contenteditable='true']",
    );
    for (let i = 0; i < cands.length; i++) {
      const r = cands[i]!.getBoundingClientRect();
      if (r.width >= 80 && r.height >= 16) return cands[i]!;
    }
    return null;
  };
  // Parse a number out of an element's text ("$1,240.00" → 1240, "23" → 23).
  const parseNum = (s: string): number | null => {
    const m = (s || "").replace(/[^0-9.\-]/g, "");
    if (!m || m === "-" || m === ".") return null;
    const n = Number(m);
    return Number.isFinite(n) ? n : null;
  };
  // The most prominent VISIBLE element whose text is purely a number (countUp "auto").
  const resolveNumber = (body: HTMLElement, target: string): HTMLElement | null => {
    if (target && target !== "auto") return body.querySelector<HTMLElement>(target);
    let best: HTMLElement | null = null;
    let bestScore = 0;
    const all = body.getElementsByTagName("*");
    for (let i = 0; i < all.length; i++) {
      const el = all[i] as HTMLElement;
      if (el.children.length !== 0) continue; // leaf text only
      const txt = (el.textContent || "").trim();
      if (!/^[$£€]?\s?-?\d[\d,]*(\.\d+)?%?$/.test(txt)) continue;
      if (parseNum(txt) === null) continue;
      const r = el.getBoundingClientRect();
      if (r.width < 12 || r.height < 12) continue;
      const score = r.width * r.height; // favor the largest/boldest number
      if (score > bestScore) { bestScore = score; best = el; }
    }
    return best;
  };
  // Deterministic integer grouping (NO toLocaleString — locale/ICU is not stable).
  const groupInt = (n: number): string => {
    const neg = n < 0;
    let s = String(Math.abs(Math.round(n)));
    let out = "";
    while (s.length > 3) { out = "," + s.slice(-3) + out; s = s.slice(0, -3); }
    return (neg ? "-" : "") + s + out;
  };
  const fmtNum = (n: number, format: string): string => {
    if (format === "currency") return "$" + groupInt(n);
    if (format === "percent") return groupInt(n) + "%";
    return groupInt(n);
  };

  type State =
    | { type: "reveal"; inst: Inst; rows: HTMLElement[]; perRowDur: number }
    | { type: "highlight"; inst: Inst; geom: Rect[]; el: HTMLElement }
    | { type: "cursor"; inst: Inst; start: { x: number; y: number }; target: { x: number; y: number }; cursorEl: HTMLElement; ringEl: HTMLElement | null }
    | { type: "type"; inst: Inst; el: HTMLElement; isInput: boolean }
    | { type: "countUp"; inst: Inst; el: HTMLElement; to: number; original: string }
    | { type: "scrollTo"; inst: Inst; el: HTMLElement; offset: number }
    | { type: "populate"; inst: Inst; rows: HTMLElement[]; perRowDur: number };
  let states: State[] | null = null;

  const makeOverlay = (css: string): HTMLElement => {
    const el = document.createElement("div");
    el.setAttribute("data-reshot-motion", "1");
    el.style.cssText = "position:absolute;pointer-events:none;z-index:9;opacity:0;" + css;
    layer.appendChild(el);
    return el;
  };

  // One-time (O(N)) resolution + overlay/initial-state setup. NEVER per-frame.
  const buildStates = (body: HTMLElement): State[] => {
    const out: State[] = [];
    const lr = layer.getBoundingClientRect();
    for (const inst of cfg.instructions) {
      if (inst.type === "reveal") {
        const rows = resolveRows(body, inst.target || "auto", inst.max || 12);
        if (rows.length === 0) continue;
        const lastStart = inst.startMs + (rows.length - 1) * (inst.stagger || 80);
        const perRowDur = Math.max(160, Math.min(600, inst.endMs - lastStart));
        for (const row of rows) {
          row.style.opacity = "0"; // no will-change (rule 2)
          row.style.transform = "translateY(" + Math.round(inst.distancePx || 12) + "px)";
        }
        out.push({ type: "reveal", inst, rows, perRowDur });
      } else if (inst.type === "highlight") {
        const rows = resolveRows(body, inst.target || "auto", inst.rows || 8);
        if (rows.length === 0) continue;
        const geom = rows.map((r) => rectRel(r, lr));
        const el = makeOverlay("border-radius:8px;background:rgba(88,101,242,0.12);border:2px solid rgb(88,101,242);");
        out.push({ type: "highlight", inst, geom, el });
      } else if (inst.type === "cursor") {
        const targetEl =
          typeof inst.to === "string" && inst.to !== "auto" ? body.querySelector(inst.to) : resolveButton(body);
        if (!targetEl) continue;
        const tr = rectRel(targetEl, lr);
        const target = { x: Math.round(tr.left + tr.width / 2), y: Math.round(tr.top + tr.height / 2) };
        const start = { x: Math.round(lr.width * (inst.fromXFrac ?? 0.5)), y: Math.round(lr.height * (inst.fromYFrac ?? 0.92)) };
        const cursorEl = makeOverlay("width:24px;height:24px;");
        cursorEl.innerHTML = "<svg width='24' height='24' viewBox='0 0 24 24'><path d='M4 2 L4 19 L8.4 14.6 L11.6 21 L14 19.9 L10.8 13.6 L17 13.6 Z' fill='#0b1220' stroke='#fff' stroke-width='1.3' stroke-linejoin='round'/></svg>";
        const ringEl = inst.click ? makeOverlay("border:2px solid rgba(88,101,242,0.9);border-radius:50%;") : null;
        out.push({ type: "cursor", inst, start, target, cursorEl, ringEl });
      } else if (inst.type === "type") {
        const el = resolveInput(body, inst.target || "auto");
        if (!el) continue;
        const isInput = el.tagName === "INPUT" || el.tagName === "TEXTAREA";
        // Start empty so the typing reads as fresh input (frame0 = empty field).
        if (isInput) (el as HTMLInputElement).value = "";
        else el.textContent = "";
        out.push({ type: "type", inst, el, isInput });
      } else if (inst.type === "countUp") {
        const el = resolveNumber(body, inst.target || "auto");
        if (!el) continue;
        const original = el.textContent || "";
        const parsed = parseNum(original);
        const to = typeof inst.to === "number" ? inst.to : parsed;
        if (to === null || to === undefined) continue; // nothing to count to
        out.push({ type: "countUp", inst, el, to, original });
      } else if (inst.type === "scrollTo") {
        // The mount root clips (overflow:hidden); "scroll" = translate the content
        // up, revealing rows below the fold. Deterministic (integer translateY).
        const content =
          inst.target && inst.target !== "auto"
            ? body.querySelector<HTMLElement>(inst.target)
            : (body as HTMLElement);
        if (!content) continue;
        const cTop = content.getBoundingClientRect().top;
        let offset: number;
        if (typeof inst.to === "string" && inst.to !== "auto") {
          const toEl = content.querySelector(inst.to);
          if (!toEl) continue;
          offset = Math.max(0, Math.round(toEl.getBoundingClientRect().top - cTop));
        } else {
          offset = Math.max(0, Math.round(content.scrollHeight - layer.getBoundingClientRect().height));
        }
        if (offset <= 0) continue; // nothing below the fold → no-op
        out.push({ type: "scrollTo", inst, el: content, offset });
      } else if (inst.type === "populate") {
        const rows = resolveRows(body, inst.target || "auto", inst.max || 12);
        if (rows.length === 0) continue;
        const lastStart = inst.startMs + (rows.length - 1) * (inst.stagger || 80);
        const perRowDur = Math.max(160, Math.min(600, inst.endMs - lastStart));
        for (const row of rows) {
          row.style.opacity = "0"; // slide in horizontally (no will-change — rule 2)
          row.style.transform = "translateX(" + Math.round(inst.distancePx || 16) + "px)";
        }
        out.push({ type: "populate", inst, rows, perRowDur });
      }
    }
    return out;
  };

  const applyReveal = (s: State & { type: "reveal" }, t: number): void => {
    for (let i = 0; i < s.rows.length; i++) {
      const p = (t - (s.inst.startMs + i * (s.inst.stagger || 80))) / s.perRowDur;
      if (p >= 1) {
        // Return-to-pristine (rule 5): byte-identical to the static reconstruction.
        s.rows[i]!.style.opacity = "";
        s.rows[i]!.style.transform = "";
      } else {
        const e = ease(p);
        s.rows[i]!.style.opacity = q8(e);
        s.rows[i]!.style.transform = "translateY(" + Math.round((1 - e) * (s.inst.distancePx || 12)) + "px)";
      }
    }
  };

  const applyHighlight = (s: State & { type: "highlight" }, t: number): void => {
    const inst = s.inst, g = s.geom, pad = inst.padPx ?? 6;
    if (t < inst.startMs || t > inst.endMs) { s.el.style.opacity = "0"; return; }
    const steps = Math.min(g.length - 1, (inst.rows || 8) - 1);
    let a = g[0]!, b = g[0]!, frac = 0;
    if (inst.walk && steps > 0) {
      const fpos = Math.min(1, (t - inst.startMs) / Math.max(1, inst.endMs - inst.startMs)) * steps;
      const idx = Math.min(steps, Math.floor(fpos));
      frac = ease(fpos - idx);
      a = g[idx]!; b = g[Math.min(steps, idx + 1)]!;
    }
    const top = a.top + (b.top - a.top) * frac;
    const left = Math.min(a.left, b.left);
    const width = Math.max(a.width, b.width);
    const height = a.height + (b.height - a.height) * frac;
    setBox(s.el, top - pad, left - pad, width + pad * 2, height + pad * 2);
    const fin = Math.min(1, (t - inst.startMs) / 150);
    const fout = Math.min(1, (inst.endMs - t) / 150);
    s.el.style.opacity = q8(0.9 * Math.max(0, Math.min(fin, fout)));
  };

  const applyCursor = (s: State & { type: "cursor" }, t: number): void => {
    const inst = s.inst;
    if (t < inst.startMs || t > inst.endMs) {
      s.cursorEl.style.opacity = "0";
      if (s.ringEl) s.ringEl.style.opacity = "0";
      return;
    }
    const moveEnd = inst.click ? inst.startMs + (inst.endMs - inst.startMs) * 0.7 : inst.endMs;
    const e = ease(Math.min(1, (t - inst.startMs) / Math.max(1, moveEnd - inst.startMs)));
    const x = Math.round(s.start.x + (s.target.x - s.start.x) * e);
    const y = Math.round(s.start.y + (s.target.y - s.start.y) * e);
    s.cursorEl.style.left = x + "px";
    s.cursorEl.style.top = y + "px";
    s.cursorEl.style.opacity = q8(0.97 * Math.min(1, (t - inst.startMs) / 120));
    if (s.ringEl) {
      if (t >= moveEnd) {
        const cp = Math.min(1, (t - moveEnd) / Math.max(1, inst.endMs - moveEnd));
        const r = Math.round(10 + cp * 26);
        setBox(s.ringEl, s.target.y - r, s.target.x - r, r * 2, r * 2);
        s.ringEl.style.opacity = q8((1 - cp) * 0.8);
      } else {
        s.ringEl.style.opacity = "0";
      }
    }
  };

  const applyType = (s: State & { type: "type" }, t: number): void => {
    const inst = s.inst;
    const text = inst.text || "";
    let shown: string;
    if (t < inst.startMs) shown = "";
    else if (t >= inst.endMs) shown = text;
    else {
      const n = Math.round(text.length * Math.min(1, (t - inst.startMs) / Math.max(1, inst.endMs - inst.startMs)));
      shown = text.slice(0, n);
    }
    // Caret blinks deterministically (on/off every 250ms of seek time) while typing.
    const typing = t >= inst.startMs && t < inst.endMs;
    const caret = inst.caret !== false && typing && Math.floor(t / 250) % 2 === 0 ? "|" : "";
    if (s.isInput) (s.el as HTMLInputElement).value = shown + (caret ? caret : "");
    else s.el.textContent = shown + caret;
  };

  const applyCountUp = (s: State & { type: "countUp" }, t: number): void => {
    const inst = s.inst;
    if (t >= inst.endMs) { s.el.textContent = s.original; return; } // return-to-pristine
    if (t < inst.startMs) { s.el.textContent = fmtNum(inst.from || 0, inst.format || "number"); return; }
    const from = inst.from || 0;
    const v = from + (s.to - from) * ease(Math.min(1, (t - inst.startMs) / Math.max(1, inst.endMs - inst.startMs)));
    s.el.textContent = fmtNum(v, inst.format || "number");
  };

  const applyScrollTo = (s: State & { type: "scrollTo" }, t: number): void => {
    const inst = s.inst;
    const p = t <= inst.startMs ? 0 : t >= inst.endMs ? 1 : ease((t - inst.startMs) / Math.max(1, inst.endMs - inst.startMs));
    const y = Math.round(s.offset * p); // integer-snapped (rule 3)
    s.el.style.transform = y === 0 ? "" : "translateY(" + -y + "px)";
  };

  const applyPopulate = (s: State & { type: "populate" }, t: number): void => {
    for (let i = 0; i < s.rows.length; i++) {
      const p = (t - (s.inst.startMs + i * (s.inst.stagger || 80))) / s.perRowDur;
      if (p >= 1) {
        s.rows[i]!.style.opacity = "";
        s.rows[i]!.style.transform = "";
      } else {
        const e = ease(p);
        s.rows[i]!.style.opacity = q8(e);
        s.rows[i]!.style.transform = "translateX(" + Math.round((1 - e) * (s.inst.distancePx || 16)) + "px)";
      }
    }
  };

  const apply = (t: number): void => {
    if (!states) return;
    for (const s of states) {
      if (s.type === "reveal") applyReveal(s, t);
      else if (s.type === "highlight") applyHighlight(s, t);
      else if (s.type === "cursor") applyCursor(s, t);
      else if (s.type === "type") applyType(s, t);
      else if (s.type === "countUp") applyCountUp(s, t);
      else if (s.type === "scrollTo") applyScrollTo(s, t);
      else applyPopulate(s, t);
    }
  };

  const tick = (): void => {
    if (states === null) {
      // Cheap retry ONLY while the artifact body hasn't mounted. Then resolve once
      // (states may be [] → motion is a no-op).
      const body = document.querySelector<HTMLElement>("[data-reshot-scene-body='1']");
      if (!body) {
        w.requestAnimationFrame(tick);
        return;
      }
      states = buildStates(body);
    }
    apply(w.performance.now());
    w.requestAnimationFrame(tick);
  };
  w.requestAnimationFrame(tick);
}

/** Source text of the in-page motion routine, for stringifying into a <script>. */
export const SCENE_MOTION_SOURCE = `(${sceneMotionInPage.toString()})();`;

/**
 * Build the inline <script> a `<Scene motion=...>` emits: writes the solved motion
 * config to a window global and starts the per-frame controller. Returns "" when
 * there is no motion so static/camera-only scenes stay untouched.
 */
export function buildSceneMotionScript(config: SceneMotionConfig | undefined): string {
  if (!config || config.instructions.length === 0) return "";
  const json = JSON.stringify(config).replace(/<\/(script)/gi, "<\\/$1");
  return `window.__RESHOT_SCENE_MOTION__ = ${json};\n${SCENE_MOTION_SOURCE}`;
}

/**
 * Build the inline <script> body a <Scene> emits: it writes the artifact payload
 * to a window global and runs the mount routine. The payload is JSON-encoded with
 * `</` escaped so the artifact HTML can never break out of the <script> element.
 */
export function buildSceneMountScript(artifact: SceneArtifact): string {
  const payload = {
    html: artifact.html,
    scrolls: artifact.scrolls ?? [],
    viewport: artifact.viewport,
  };
  const json = JSON.stringify(payload).replace(/<\/(script)/gi, "<\\/$1");
  return `window.__RESHOT_SCENE__ = ${json};\n${MOUNT_SCENE_SOURCE}`;
}
