import type { ComposeNode } from "../jsx-runtime.js";
import { useWorkflowContext } from "../timeline/context.js";
import { Annotation } from "./Annotation.js";
import { FocusPath } from "./FocusPath.js";
import { Frame, type FrameProps } from "./Frame.js";
import { stableClassPart, type ProductFilmTone } from "./product-film-utils.js";

export type ProductFilmStep = {
  id: string;
  at: string;
  until?: string;
  target?: string;
  label?: string;
  tone?: ProductFilmTone;
  camera?: "auto" | "wide" | "hold";
};

export type ProductFilmProps = {
  src?: string;
  url?: string;
  chrome?: FrameProps["chrome"];
  fit?: FrameProps["fit"];
  steps: ProductFilmStep[];
  children?: ComposeNode;
};

export function ProductFilm({
  src,
  url,
  chrome = "none",
  fit = "contain",
  steps,
  children,
}: ProductFilmProps): ComposeNode {
  const { slug } = useWorkflowContext();
  const focusClass = `reshot-product-film-${stableClassPart(slug)}`;
  const annotations = steps
    .filter((step) => step.target && step.label)
    .map((step) => (
      <Annotation
        at={step.at}
        until={step.until}
        target={step.target}
        chrome={chrome}
        tone={step.tone}
      >
        {step.label}
      </Annotation>
    ));

  return (
    <div className={`reshot-product-film ${focusClass}`}>
      <Frame chrome={chrome} url={url} src={src} fit={fit}>
        <FocusPath steps={steps} className={focusClass} />
        {annotations}
        {children}
      </Frame>
    </div>
  );
}
