import type { ComposeNode } from "../jsx-runtime.js";
import { useWorkflowContext } from "../timeline/context.js";

export type FrameProps = {
  chrome?: "none" | "minimal" | "browser-light" | "browser-dark";
  url?: string;
  src?: string;
  fit?: "contain" | "cover";
  children?: ComposeNode;
};

export function Frame({
  chrome = "none",
  url = "app.reshot.dev",
  src,
  fit = "contain",
  children,
}: FrameProps): ComposeNode {
  const context = useWorkflowContext();
  const mediaSrc = src ?? context.capturePath ?? "";
  const isStillImage = /\.(?:png|jpe?g|webp|gif|avif|svg)(?:[?#].*)?$/i.test(
    mediaSrc,
  );
  const showChrome = chrome !== "none";
  const mediaClassName = `reshot-frame__media${
    fit === "cover" ? " reshot-frame__media--cover" : ""
  }`;

  return (
    <div className={`reshot-frame reshot-frame--${chrome}`} data-product-surface="true">
      {showChrome ? (
        <div className="reshot-frame__chrome">
          <div className="reshot-frame__traffic" aria-hidden="true">
            <span />
            <span />
            <span />
          </div>
          <div className="reshot-frame__url">{url}</div>
        </div>
      ) : null}
      <div className="reshot-frame__viewport">
        <div className="reshot-frame__media-layer">
          {isStillImage ? (
            <img
              className={mediaClassName}
              src={mediaSrc}
              alt=""
              aria-hidden="true"
            />
          ) : (
            <video
              className={mediaClassName}
              src={mediaSrc}
              autoPlay
              muted
              playsInline
              preload="auto"
            />
          )}
        </div>
        <div className="reshot-frame__overlays">{children}</div>
      </div>
    </div>
  );
}
