import {
  Fragment,
  type ComposeComponent,
  type ComposeElement,
  type ComposeNode,
} from "../jsx-runtime.js";
import {
  WorkflowContextProvider,
  type WorkflowContextValue,
  withWorkflowContext,
} from "../timeline/context.js";

export type CompileResult = {
  html: string;
  styles: string[];
};

type CompileContext = {
  styles: string[];
};

const VOID_ELEMENTS = new Set([
  "area",
  "base",
  "br",
  "col",
  "embed",
  "hr",
  "img",
  "input",
  "link",
  "meta",
  "param",
  "source",
  "track",
  "wbr",
]);

const UNITLESS_CSS = new Set([
  "aspectRatio",
  "columnCount",
  "flex",
  "flexGrow",
  "flexShrink",
  "fontWeight",
  "lineHeight",
  "opacity",
  "order",
  "scale",
  "zIndex",
  "zoom",
]);

export function compile(node: ComposeNode): CompileResult {
  const context: CompileContext = { styles: [] };
  return {
    html: renderNode(node, context),
    styles: context.styles,
  };
}

export function compileToHtml(node: ComposeNode): string {
  return compile(node).html;
}

function isComposeElement(value: unknown): value is ComposeElement {
  return (
    typeof value === "object" &&
    value !== null &&
    (value as { $$compose?: unknown }).$$compose === true
  );
}

function childrenProp(children: ComposeNode[]): ComposeNode | undefined {
  if (children.length === 0) return undefined;
  if (children.length === 1) return children[0];
  return children;
}

function renderNode(node: ComposeNode, context: CompileContext): string {
  if (node == null || node === false || node === true) return "";
  if (typeof node === "string") return escapeText(node);
  if (typeof node === "number") return escapeText(String(node));
  if (Array.isArray(node)) {
    return node.map((child) => renderNode(child, context)).join("");
  }
  if (!isComposeElement(node)) return "";

  if (node.type === Fragment) {
    return node.children.map((child) => renderNode(child, context)).join("");
  }

  if (node.type === WorkflowContextProvider) {
    const value = node.props.value as WorkflowContextValue;
    return withWorkflowContext(value, () =>
      node.children.map((child) => renderNode(child, context)).join(""),
    );
  }

  if (typeof node.type === "function") {
    const component = node.type as ComposeComponent;
    const rendered = component({
      ...node.props,
      children: childrenProp(node.children),
    });
    return renderNode(rendered, context);
  }

  if (typeof node.type !== "string") return "";

  const attrs = serializeAttrs(node.props);
  if (VOID_ELEMENTS.has(node.type)) {
    return `<${node.type}${attrs} />`;
  }

  if (node.type === "style") {
    const css = rawTextContent(node.children);
    context.styles.push(css);
    return `<style${attrs}>${css}</style>`;
  }

  if (node.type === "script") {
    return `<script${attrs}>${rawTextContent(node.children)}</script>`;
  }

  const inner = node.children.map((child) => renderNode(child, context)).join("");
  return `<${node.type}${attrs}>${inner}</${node.type}>`;
}

function serializeAttrs(props: Record<string, unknown>): string {
  const attrs: string[] = [];
  for (const [rawName, rawValue] of Object.entries(props)) {
    if (rawName === "children" || rawName === "key" || rawName === "ref") {
      continue;
    }
    if (rawValue == null || rawValue === false) continue;

    const name = attrName(rawName);
    if (rawValue === true) {
      attrs.push(name);
      continue;
    }

    if (name === "style" && typeof rawValue === "object") {
      const css = styleObjectToString(rawValue as Record<string, unknown>);
      if (css) attrs.push(`style="${escapeAttr(css)}"`);
      continue;
    }

    attrs.push(`${name}="${escapeAttr(String(rawValue))}"`);
  }

  return attrs.length === 0 ? "" : ` ${attrs.join(" ")}`;
}

function attrName(name: string): string {
  switch (name) {
    case "charSet":
      return "charset";
    case "className":
      return "class";
    case "crossOrigin":
      return "crossorigin";
    case "autoPlay":
      return "autoplay";
    case "htmlFor":
      return "for";
    case "playsInline":
      return "playsinline";
    default:
      return name;
  }
}

function styleObjectToString(style: Record<string, unknown>): string {
  const parts: string[] = [];
  for (const [key, value] of Object.entries(style)) {
    if (value == null || value === false) continue;
    const cssName = key.startsWith("--") ? key : camelToKebab(key);
    const cssValue =
      typeof value === "number" && !UNITLESS_CSS.has(key)
        ? `${value}px`
        : String(value);
    parts.push(`${cssName}: ${cssValue}`);
  }
  return parts.join("; ");
}

function rawTextContent(nodes: ComposeNode[]): string {
  return nodes
    .map((node) => {
      if (node == null || node === false || node === true) return "";
      if (typeof node === "string" || typeof node === "number") {
        return String(node);
      }
      if (Array.isArray(node)) return rawTextContent(node);
      return "";
    })
    .join("");
}

function camelToKebab(value: string): string {
  return value.replace(/[A-Z]/g, (match) => `-${match.toLowerCase()}`);
}

function escapeText(value: string): string {
  return value
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;");
}

function escapeAttr(value: string): string {
  return value.replace(/&/g, "&amp;").replace(/"/g, "&quot;");
}
