import {
  solveCameraPath,
  type CameraStrategy,
  type StepInput,
} from "@reshot/motion-core";

import type { WorkflowMetadata } from "../timeline/context.js";
import {
  readSourceSize,
  readTargetRect,
  timingFor,
  type NormalizedRect,
} from "./product-film-utils.js";
import type { ProductFilmStep } from "./ProductFilm.js";

export type CameraSolverSettings = {
  mode?: "cinematic" | "static" | "manual";
  damping?: number;
  padding?: number;
};

export type TimedCameraStep = {
  step: ProductFilmStep;
  timing: ReturnType<typeof timingFor>;
};

export type SolvedProductFilmCameraPath = {
  source: { width: number; height: number };
  timedSteps: TimedCameraStep[];
  solved: ReturnType<typeof solveCameraPath>;
};

export type SolveProductFilmCameraPathOptions = {
  settings?: CameraSolverSettings;
  sampleIntervalMs?: number;
  includeHoldTargetBounds?: boolean;
};

export const DEFAULT_CAMERA_SOLVER_SETTINGS = {
  mode: "cinematic",
  damping: 0.55,
  padding: 2.4,
} as const;

export function solveProductFilmCameraPath(
  steps: ProductFilmStep[],
  workflow: WorkflowMetadata,
  options: SolveProductFilmCameraPathOptions = {},
): SolvedProductFilmCameraPath {
  const source = readSourceSize(workflow);
  const timedSteps = steps.map((step) => ({
    step,
    timing: timingFor(step.at, step.until, workflow.timeline ?? []),
  }));

  if (timedSteps.length === 0) {
    return { source, timedSteps, solved: [] };
  }

  const solverInput: StepInput[] = timedSteps.map(({ step, timing }) => ({
    id: step.id,
    action: step.camera === "wide" ? "navigate" : step.id,
    bounds: targetBoundsForStep(step, workflow, source, options),
    durationMs: Math.max(1, timing.durationMs),
    transitionDurationMs: 0,
    camera: { strategy: cameraStrategy(step.camera) },
  }));

  const solved = solveCameraPath({
    steps: solverInput,
    imageWidth: source.width,
    imageHeight: source.height,
    settings: {
      mode: options.settings?.mode ?? DEFAULT_CAMERA_SOLVER_SETTINGS.mode,
      damping:
        options.settings?.damping ?? DEFAULT_CAMERA_SOLVER_SETTINGS.damping,
      padding:
        options.settings?.padding ?? DEFAULT_CAMERA_SOLVER_SETTINGS.padding,
    },
    sampleIntervalMs: options.sampleIntervalMs,
  });

  return { source, timedSteps, solved };
}

function cameraStrategy(camera: ProductFilmStep["camera"]): CameraStrategy {
  if (camera === "wide") return "wide";
  if (camera === "hold") return "fix";
  return "auto";
}

function targetBoundsForStep(
  step: ProductFilmStep,
  workflow: WorkflowMetadata,
  source: { width: number; height: number },
  options: SolveProductFilmCameraPathOptions,
): NormalizedRect {
  const target = step.target;
  const shouldReadTarget =
    typeof target === "string" &&
    step.camera !== "wide" &&
    (step.camera !== "hold" || options.includeHoldTargetBounds === true);

  if (shouldReadTarget) {
    return readTargetRect(workflow, target);
  }

  return { x: 0, y: 0, width: source.width, height: source.height };
}
