import type { ComposeElement, ComposeNode } from "../jsx-runtime.js";
import { normalizeChildren } from "../jsx-runtime.js";

export type TimelineEvent = {
  type?: string;
  name?: string;
  tMs?: number;
  timestampMs?: number;
  [key: string]: unknown;
};

export type WorkflowMetadata = {
  durationMs?: number;
  timeline?: TimelineEvent[];
  targets?: Record<string, unknown>;
  source?: unknown;
  captureSize?: unknown;
  capturePath?: string;
  [key: string]: unknown;
};

export type WorkflowContextValue = {
  workflow: WorkflowMetadata;
  slug: string;
  capturePath?: string;
};

export const WorkflowContextProvider: unique symbol = Symbol(
  "WorkflowContextProvider",
);

const workflowStack: WorkflowContextValue[] = [];

export function createWorkflowProvider(
  value: WorkflowContextValue,
  children: ComposeNode,
): ComposeElement {
  return {
    $$compose: true,
    type: WorkflowContextProvider,
    props: { value },
    children: normalizeChildren(children),
  };
}

export function withWorkflowContext<T>(
  value: WorkflowContextValue,
  fn: () => T,
): T {
  workflowStack.push(value);
  try {
    return fn();
  } finally {
    workflowStack.pop();
  }
}

export function getWorkflowContext(): WorkflowContextValue | undefined {
  return workflowStack[workflowStack.length - 1];
}

export function useWorkflowContext(): WorkflowContextValue {
  const context = getWorkflowContext();
  if (!context) {
    throw new Error(
      "Compose primitive used outside <Composition>. Wrap the tree in <Composition workflow={...}>.",
    );
  }
  return context;
}
