import type { TimelineEvent } from "./context.js";

export type BeatTiming = {
  startMs: number;
  endMs: number;
  durationMs: number;
};

const DEFAULT_DURATION_MS = 1800;

export function resolveBeatTiming(
  at: string,
  until: string | undefined,
  timeline: TimelineEvent[],
): BeatTiming {
  const startIndex = findTimelineIndex(at, timeline);
  if (startIndex === -1) {
    throw new Error(`Timeline event "${at}" was not found.`);
  }

  const startEvent = timeline[startIndex];
  if (!startEvent) {
    throw new Error(`Timeline event "${at}" was not found.`);
  }

  const startMs = eventTimeMs(startEvent, at);
  const endMs = until
    ? eventTimeMs(findTimelineEvent(until, timeline), until)
    : nextEventTimeMs(startIndex, timeline) ?? startMs + DEFAULT_DURATION_MS;

  if (endMs <= startMs) {
    throw new Error(
      `Timeline event "${until ?? "next"}" must be after "${at}".`,
    );
  }

  return {
    startMs,
    endMs,
    durationMs: endMs - startMs,
  };
}

function findTimelineEvent(key: string, timeline: TimelineEvent[]): TimelineEvent {
  const event = timeline[findTimelineIndex(key, timeline)];
  if (!event) {
    throw new Error(`Timeline event "${key}" was not found.`);
  }
  return event;
}

function findTimelineIndex(key: string, timeline: TimelineEvent[]): number {
  return timeline.findIndex((event) => eventMatches(event, key));
}

function eventMatches(event: TimelineEvent, key: string): boolean {
  return ["id", "name", "type", "key", "label", "slug"].some(
    (field) => event[field] === key,
  );
}

function nextEventTimeMs(
  startIndex: number,
  timeline: TimelineEvent[],
): number | undefined {
  for (const event of timeline.slice(startIndex + 1)) {
    const time = maybeEventTimeMs(event);
    if (typeof time === "number") return time;
  }
  return undefined;
}

function eventTimeMs(event: TimelineEvent, key: string): number {
  const time = maybeEventTimeMs(event);
  if (typeof time !== "number") {
    throw new Error(`Timeline event "${key}" is missing a numeric tMs value.`);
  }
  return time;
}

function maybeEventTimeMs(event: TimelineEvent): number | undefined {
  for (const field of ["tMs", "timestampMs", "timeMs", "ms"]) {
    const value = event[field];
    if (typeof value === "number" && Number.isFinite(value)) return value;
  }
  return undefined;
}
