import type { ComposeNode } from "../jsx-runtime.js";
import { useWorkflowContext } from "../timeline/context.js";
import { solveProductFilmCameraPath } from "./camera-solver.js";
import {
  fullStageScale,
  stableClassPart,
} from "./product-film-utils.js";
import type { ProductFilmStep } from "./ProductFilm.js";

export type FocusPathProps = {
  steps: ProductFilmStep[];
  className?: string;
};

export function FocusPath({ steps, className }: FocusPathProps): ComposeNode {
  const { workflow, slug } = useWorkflowContext();
  const focusClass =
    className ?? `reshot-focus-${stableClassPart(slug)}-${steps.length}`;
  // A `camera:"hold"` step is NOT dropped — it maps to motion-core's `'fix'`
  // strategy (lock the camera to the previous step's framing). Dropping it would
  // silently shorten the solved path and break the timeline alignment.
  const { source, timedSteps, solved } = solveProductFilmCameraPath(
    steps,
    workflow,
    { includeHoldTargetBounds: true },
  );

  if (timedSteps.length === 0) {
    return <div data-focus-path={focusClass} hidden />;
  }

  const firstStartMs = timedSteps[0]?.timing.startMs ?? 0;
  const totalMs = Math.max(
    1,
    timedSteps[timedSteps.length - 1]?.timing.endMs ?? workflow.durationMs ?? 1,
  );
  const keyframes = solved
    .map((frame) => {
      const absoluteMs = firstStartMs + frame.timeMs;
      const percent = Math.max(0, Math.min(100, (absoluteMs / totalMs) * 100));
      return `${percent.toFixed(3)}% { transform: ${transformFor(
        frame.viewport.x,
        frame.viewport.y,
        frame.viewport.zoom,
        source.width,
        source.height,
      )}; }`;
    })
    .join("\n");
  const firstTransform = solved[0]
    ? transformFor(
        solved[0].viewport.x,
        solved[0].viewport.y,
        solved[0].viewport.zoom,
        source.width,
        source.height,
      )
    : "translate(0px, 0px) scale(1)";
  const last = solved[solved.length - 1];
  const lastTransform = last
    ? transformFor(
        last.viewport.x,
        last.viewport.y,
        last.viewport.zoom,
        source.width,
        source.height,
      )
    : firstTransform;

  return (
    <>
      <style>{`
.${focusClass} .reshot-frame__media-layer,
.${focusClass} .reshot-frame__overlays {
  transform: ${firstTransform};
  animation: ${focusClass}-camera ${totalMs}ms linear forwards;
}
@keyframes ${focusClass}-camera {
0% { transform: ${firstTransform}; }
${keyframes}
100% { transform: ${lastTransform}; }
}
`}</style>
      <div data-focus-path={focusClass} hidden />
    </>
  );
}

function transformFor(
  x: number,
  y: number,
  zoom: number,
  sourceWidth: number,
  sourceHeight: number,
): string {
  const { scaleX, scaleY } = fullStageScale({
    width: sourceWidth,
    height: sourceHeight,
  });
  const tx = Math.round(-x * scaleX * zoom * 100) / 100;
  const ty = Math.round(-y * scaleY * zoom * 100) / 100;
  const roundedZoom = Math.round(zoom * 1000) / 1000;
  return `translate(${tx}px, ${ty}px) scale(${roundedZoom})`;
}
